import{_ as s,o as a,c as i,a2 as e}from"./chunks/framework.CGYl2SZ_.js";const t=JSON.parse('{"title":"date time","description":"date time 页面","frontmatter":{"title":"date time","description":"date time 页面"},"headers":[],"relativePath":"tools/date-time.md","filePath":"tools/date-time.md"}');const n=s({name:"tools/date-time.md"},[["render",function(s,t,n,l,p,o){return a(),i("div",null,[...t[0]||(t[0]=[e('<h1 id="日期和时间" tabindex="-1">日期和时间 <a class="header-anchor" href="#日期和时间" aria-label="Permalink to &quot;日期和时间&quot;">​</a></h1><p>OpenClaw 默认为<strong>传输时间戳使用主机本地时间</strong>，<strong>仅在系统提示中使用用户时区</strong>。 保留提供商时间戳，以便工具保持其原生语义（当前时间可通过 <code>session_status</code> 获取）。</p><h2 id="消息信封-默认本地" tabindex="-1">消息信封（默认本地） <a class="header-anchor" href="#消息信封-默认本地" aria-label="Permalink to &quot;消息信封（默认本地）&quot;">​</a></h2><p>入站消息带有时间戳包裹（分钟精度）：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Provider ... 2026-01-05 16:26 PST] message text</span></span></code></pre></div><p>此信封时间戳<strong>默认使用主机本地</strong>，无论提供商时区如何。</p><p>你可以覆盖此行为：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      envelopeTimezone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;local&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;utc&quot; | &quot;local&quot; | &quot;user&quot; | IANA timezone</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      envelopeTimestamp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;on&quot; | &quot;off&quot;</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      envelopeElapsed</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;on&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// &quot;on&quot; | &quot;off&quot;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><code>envelopeTimezone: &quot;utc&quot;</code> 使用 UTC。</li><li><code>envelopeTimezone: &quot;local&quot;</code> 使用主机时区。</li><li><code>envelopeTimezone: &quot;user&quot;</code> 使用 <code>agents.defaults.userTimezone</code>（回退到主机时区）。</li><li>使用显式 IANA 时区（例如 <code>&quot;America/Chicago&quot;</code>）用于固定区域。</li><li><code>envelopeTimestamp: &quot;off&quot;</code> 从信封头中移除绝对时间戳。</li><li><code>envelopeElapsed: &quot;off&quot;</code> 移除经过时间后缀（<code>+2m</code> 样式）。</li></ul><h3 id="示例" tabindex="-1">示例 <a class="header-anchor" href="#示例" aria-label="Permalink to &quot;示例&quot;">​</a></h3><p><strong>本地（默认）：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[WhatsApp +1555 2026-01-18 00:19 PST] hello</span></span></code></pre></div><p><strong>用户时区：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[WhatsApp +1555 2026-01-18 00:19 CST] hello</span></span></code></pre></div><p><strong>启用经过时间：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[WhatsApp +1555 +30s 2026-01-18T05:19Z] follow-up</span></span></code></pre></div><h2 id="系统提示-当前日期和时间" tabindex="-1">系统提示：当前日期和时间 <a class="header-anchor" href="#系统提示-当前日期和时间" aria-label="Permalink to &quot;系统提示：当前日期和时间&quot;">​</a></h2><p>如果知道用户时区，系统提示包含专用的<strong>当前日期和时间</strong>部分，仅包含<strong>时区</strong>（无时钟/时间格式）以保持提示缓存稳定：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Time zone: America/Chicago</span></span></code></pre></div><p>当代理需要当前时间时，使用 <code>session_status</code> 工具；状态卡包含时间戳行。</p><h2 id="系统事件行-默认本地" tabindex="-1">系统事件行（默认本地） <a class="header-anchor" href="#系统事件行-默认本地" aria-label="Permalink to &quot;系统事件行（默认本地）&quot;">​</a></h2><p>插入代理上下文的排队系统事件使用与消息信封相同的时区选择（默认：主机本地）前缀：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System: [2026-01-12 12:19:17 PST] Model switched.</span></span></code></pre></div><h3 id="配置用户时区-格式" tabindex="-1">配置用户时区 + 格式 <a class="header-anchor" href="#配置用户时区-格式" aria-label="Permalink to &quot;配置用户时区 + 格式&quot;">​</a></h3><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agents</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    defaults</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      userTimezone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;America/Chicago&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      timeFormat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;auto&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// auto | 12 | 24</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><code>userTimezone</code> 设置提示上下文的<strong>用户本地时区</strong>。</li><li><code>timeFormat</code> 控制提示中的 <strong>12h/24h 显示</strong>。<code>auto</code> 遵循操作系统偏好。</li></ul><h2 id="时间格式检测-自动" tabindex="-1">时间格式检测（自动） <a class="header-anchor" href="#时间格式检测-自动" aria-label="Permalink to &quot;时间格式检测（自动）&quot;">​</a></h2><p>当 <code>timeFormat: &quot;auto&quot;</code> 时，OpenClaw 检查操作系统偏好（macOS/Windows）并回退到区域设置格式。检测到的值<strong>按进程缓存</strong>以避免重复系统调用。</p><h2 id="工具有效载荷-连接器-原始提供商时间-规范化字段" tabindex="-1">工具有效载荷 + 连接器（原始提供商时间 + 规范化字段） <a class="header-anchor" href="#工具有效载荷-连接器-原始提供商时间-规范化字段" aria-label="Permalink to &quot;工具有效载荷 + 连接器（原始提供商时间 + 规范化字段）&quot;">​</a></h2><p>渠道工具返回<strong>提供商原生时间戳</strong>，并添加规范化字段以保持一致性：</p><ul><li><code>timestampMs</code>：纪元毫秒（UTC）</li><li><code>timestampUtc</code>：ISO 8601 UTC 字符串</li></ul><p>保留原始提供商字段以免丢失任何内容。</p><ul><li>Slack：来自 API 的类似纪元的字符串</li><li>Discord：UTC ISO 时间戳</li><li>Telegram/WhatsApp：提供商特定的数字/ISO 时间戳</li></ul><p>如果你需要本地时间，使用已知时区在下游转换它。</p><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/concepts/system-prompt.html">System Prompt</a></li><li><a href="/concepts/timezone.html">Timezones</a></li><li><a href="/concepts/messages.html">Messages</a></li></ul>',36)])])}]]);export{t as __pageData,n as default};
